     7→/// Plugin metadata returned by `prb_plugin_info()`.
     8→///
     9→/// All string fields are null-terminated UTF-8 C strings. The plugin is
    10→/// responsible for keeping these strings alive for the lifetime of the plugin.
    11→#[repr(C)]
    12→pub struct PluginInfo {
