    14→    pub name: *const c_char,
    15→    /// Plugin version (null-terminated UTF-8, semver).
    16→    pub version: *const c_char,
    17→    /// Plugin description (null-terminated UTF-8).
    18→    pub description: *const c_char,
    19→    /// API version this plugin was compiled against.
    20→    pub api_version: *const c_char,
    21→    /// Protocol ID this plugin handles (null-terminated UTF-8).
