    29→    pub detected: u8,
    30→    /// Confidence (0.0 - 1.0).
    31→    pub confidence: f32,
    32→}
    33→
    34→/// Buffer for passing data across the FFI boundary.
    35→///
    36→/// The buffer is not owned by the recipient; the data pointer is only
    37→/// valid for the duration of the function call.
    38→#[repr(C)]
    39→pub struct ByteBuffer {
    40→    pub ptr: *const u8,
    41→    pub len: usize,
    42→}
    43→
    44→impl ByteBuffer {
    45→    /// Create a ByteBuffer from a byte slice.
    46→    ///
    47→    /// # Safety
    48→    /// The returned buffer is only valid as long as the slice remains valid.
    49→    pub fn from_slice(data: &[u8]) -> Self {
    50→        Self {
    51→            ptr: data.as_ptr(),
    52→            len: data.len(),
    53→        }
    54→    }
    55→
    56→    /// Convert the buffer to a byte slice.
    57→    ///
    58→    /// # Safety
    59→    /// The caller must ensure the pointer is valid and the length is correct.
    60→    pub unsafe fn as_slice<'a>(&self) -> &'a [u8] {
    61→        if self.ptr.is_null() {
    62→            &[]
    63→        } else {
    64→            unsafe { std::slice::from_raw_parts(self.ptr, self.len) }
    65→        }
    66→    }
    67→}
    68→
    69→/// Owned buffer allocated by the plugin, freed by the host.
    70→///
    71→/// The plugin allocates this buffer using `Vec::into_raw_parts()` and the
    72→/// host frees it by calling `prb_plugin_buffer_free()`.
    73→#[repr(C)]
    74→pub struct OwnedBuffer {
    75→    pub ptr: *mut u8,
    76→    pub len: usize,
    77→    pub capacity: usize,
    78→}
