   110→}
   111→
   112→/// Opaque decoder handle.
   113→///
   114→/// The plugin creates this handle in `prb_plugin_decoder_create()` and
   115→/// the host passes it to subsequent `prb_plugin_decode()` calls.
   116→pub type DecoderHandle = *mut c_void;
   117→
   118→/// Safe Rust trait that native plugin authors implement.
   119→///
   120→/// The `prb_export_plugin!` macro generates the C FFI wrappers around
   121→/// implementations of this trait.
   122→pub trait PluginDecoder: Send {
   123→    /// Return plugin metadata.
   124→    fn info() -> crate::PluginMetadata
   125→    where
   126→        Self: Sized;
   127→
   128→    /// Detect whether this plugin can decode the given data.
   129→    ///
   130→    /// Returns `Some(confidence)` where confidence is in [0.0, 1.0] if
   131→    /// the plugin can handle this data, or `None` if it cannot.
   132→    fn detect(ctx: &crate::DetectContext) -> Option<f32>
   133→    where
   134→        Self: Sized;
   135→
   136→    /// Create a new decoder instance.
   137→    fn new() -> Self
   138→    where
   139→        Self: Sized;
   140→
   141→    /// Decode a byte stream chunk.
   142→    ///
   143→    /// Returns a vector of decoded events, or an error message on failure.
   144→    fn decode(&mut self, data: &[u8], ctx: &crate::DecodeCtx) -> Result<Vec<crate::DebugEventDto>, String>;
   145→}
   146→
   147→/// Macro to implement all required C ABI exports from a Rust struct.
   148→///
   149→/// # Usage
   150→///
   151→/// ```no_run
   152→/// use prb_plugin_api::*;
   153→/// use prb_plugin_api::native::*;
   154→///
   155→/// struct MyDecoder { /* ... */ }
   156→///
   157→/// impl PluginDecoder for MyDecoder {
   158→///     fn info() -> PluginMetadata {
   159→///         PluginMetadata {
   160→///             name: "my-decoder".into(),
   161→///             version: "0.1.0".into(),
   162→///             description: "Custom decoder".into(),
   163→///             protocol_id: "custom".into(),
   164→///             api_version: prb_plugin_api::API_VERSION.into(),
   165→///         }
   166→///     }
   167→///
   168→///     fn detect(ctx: &DetectContext) -> Option<f32> {
   169→///         None
   170→///     }
   171→///
   172→///     fn new() -> Self {
   173→///         Self { /* ... */ }
   174→///     }
   175→///
   176→///     fn decode(&mut self, data: &[u8], ctx: &DecodeCtx) -> Result<Vec<DebugEventDto>, String> {
   177→///         Ok(vec![])
   178→///     }
   179→/// }
   180→///
   181→/// prb_export_plugin!(MyDecoder);
   182→/// ```
   183→#[macro_export]
   184→macro_rules! prb_export_plugin {
   185→    ($decoder_type:ty) => {
   186→        use std::ffi::CString;
   187→        use std::os::raw::{c_char, c_void};
   188→        use std::panic::{catch_unwind, AssertUnwindSafe};
   189→
   190→        // Static strings for plugin info (must outlive the plugin)
   191→        static mut PLUGIN_NAME: Option<CString> = None;
   192→        static mut PLUGIN_VERSION: Option<CString> = None;
   193→        static mut PLUGIN_DESCRIPTION: Option<CString> = None;
   194→        static mut PLUGIN_API_VERSION: Option<CString> = None;
   195→        static mut PLUGIN_PROTOCOL_ID: Option<CString> = None;
   196→
   197→        /// Initialize plugin metadata strings.
   198→        fn init_plugin_strings() {
   199→            use $crate::native::PluginDecoder;
   200→
   201→            let info = <$decoder_type>::info();
   202→
   203→            unsafe {
   204→                PLUGIN_NAME = Some(CString::new(info.name).expect("null byte in plugin name"));
   205→                PLUGIN_VERSION =
   206→                    Some(CString::new(info.version).expect("null byte in plugin version"));
   207→                PLUGIN_DESCRIPTION = Some(
   208→                    CString::new(info.description).expect("null byte in plugin description"),
   209→                );
   210→                PLUGIN_API_VERSION =
   211→                    Some(CString::new(info.api_version).expect("null byte in API version"));
   212→                PLUGIN_PROTOCOL_ID = Some(
   213→                    CString::new(info.protocol_id).expect("null byte in protocol ID"),
   214→                );
   215→            }
   216→        }
   217→
   218→        #[no_mangle]
   219→        pub extern "C" fn prb_plugin_info() -> $crate::native::PluginInfo {
   220→            init_plugin_strings();
   221→
   222→            unsafe {
   223→                $crate::native::PluginInfo {
   224→                    name: PLUGIN_NAME
   225→                        .as_ref()
   226→                        .expect("plugin name not initialized")
   227→                        .as_ptr(),
   228→                    version: PLUGIN_VERSION
   229→                        .as_ref()
   230→                        .expect("plugin version not initialized")
   231→                        .as_ptr(),
   232→                    description: PLUGIN_DESCRIPTION
   233→                        .as_ref()
   234→                        .expect("plugin description not initialized")
   235→                        .as_ptr(),
   236→                    api_version: PLUGIN_API_VERSION
   237→                        .as_ref()
   238→                        .expect("API version not initialized")
   239→                        .as_ptr(),
   240→                    protocol_id: PLUGIN_PROTOCOL_ID
   241→                        .as_ref()
   242→                        .expect("protocol ID not initialized")
   243→                        .as_ptr(),
   244→                }
   245→            }
   246→        }
   247→
   248→        #[no_mangle]
   249→        pub extern "C" fn prb_plugin_detect(
   250→            data: $crate::native::ByteBuffer,
   251→            src_port: u16,
   252→            dst_port: u16,
   253→            transport: u8,
   254→        ) -> $crate::native::DetectResultFfi {
   255→            use $crate::native::PluginDecoder;
   256→
   257→            let result = catch_unwind(AssertUnwindSafe(|| {
   258→                let data_slice = unsafe { data.as_slice() };
   259→                let transport = match transport {
   260→                    0 => $crate::TransportLayer::Tcp,
   261→                    1 => $crate::TransportLayer::Udp,
   262→                    _ => return None,
   263→                };
   264→
   265→                let ctx = $crate::DetectContext {
   266→                    initial_bytes: data_slice.to_vec(),
   267→                    src_port,
   268→                    dst_port,
   269→                    transport,
   270→                    #[cfg(feature = "wasm-pdk")]
   271→                    initial_bytes_b64: String::new(),
   272→                };
   273→
   274→                <$decoder_type>::detect(&ctx)
   275→            }));
   276→
   277→            match result {
   278→                Ok(Some(confidence)) => $crate::native::DetectResultFfi {
   279→                    detected: 1,
   280→                    confidence: confidence.clamp(0.0, 1.0),
   281→                },
   282→                _ => $crate::native::DetectResultFfi {
   283→                    detected: 0,
   284→                    confidence: 0.0,
   285→                },
   286→            }
   287→        }
   288→
   289→        #[no_mangle]
   290→        pub extern "C" fn prb_plugin_decoder_create() -> *mut c_void {
   291→            use $crate::native::PluginDecoder;
   292→
   293→            let result = catch_unwind(AssertUnwindSafe(|| {
   294→                let decoder = <$decoder_type>::new();
   295→                Box::into_raw(Box::new(decoder)) as *mut c_void
   296→            }));
   297→
   298→            result.unwrap_or(std::ptr::null_mut())
   299→        }
   300→
   301→        #[no_mangle]
   302→        pub extern "C" fn prb_plugin_decode(
   303→            handle: *mut c_void,
   304→            data: $crate::native::ByteBuffer,
   305→            ctx_json: $crate::native::ByteBuffer,
   306→        ) -> $crate::native::OwnedBuffer {
   307→            use $crate::native::PluginDecoder;
   308→
   309→            let result = catch_unwind(AssertUnwindSafe(|| {
   310→                if handle.is_null() {
   311→                    return $crate::native::OwnedBuffer::empty();
   312→                }
   313→
   314→                let decoder = unsafe { &mut *(handle as *mut $decoder_type) };
   315→                let data_slice = unsafe { data.as_slice() };
   316→                let ctx_json_slice = unsafe { ctx_json.as_slice() };
   317→
   318→                // Deserialize context
   319→                let ctx: $crate::DecodeCtx = match serde_json::from_slice(ctx_json_slice) {
   320→                    Ok(ctx) => ctx,
   321→                    Err(_) => return $crate::native::OwnedBuffer::empty(),
   322→                };
   323→
   324→                // Decode
   325→                let events = match decoder.decode(data_slice, &ctx) {
   326→                    Ok(events) => events,
   327→                    Err(_) => return $crate::native::OwnedBuffer::empty(),
   328→                };
   329→
   330→                // Serialize events to JSON
   331→                let json = match serde_json::to_vec(&events) {
   332→                    Ok(json) => json,
   333→                    Err(_) => return $crate::native::OwnedBuffer::empty(),
   334→                };
   335→
   336→                $crate::native::OwnedBuffer::from_vec(json)
   337→            }));
   338→
   339→            result.unwrap_or_else(|_| $crate::native::OwnedBuffer::empty())
   340→        }
   341→
   342→        #[no_mangle]
   343→        pub extern "C" fn prb_plugin_buffer_free(buf: $crate::native::OwnedBuffer) {
   344→            if !buf.ptr.is_null() {
   345→                let _ = catch_unwind(AssertUnwindSafe(|| {
   346→                    let _vec = unsafe { buf.into_vec() };
   347→                    // Vec is dropped here
   348→                }));
   349→            }
   350→        }
   351→
   352→        #[no_mangle]
   353→        pub extern "C" fn prb_plugin_decoder_destroy(handle: *mut c_void) {
   354→            if !handle.is_null() {
   355→                let _ = catch_unwind(AssertUnwindSafe(|| {
   356→                    let _decoder = unsafe { Box::from_raw(handle as *mut $decoder_type) };
   357→                    // Decoder is dropped here
   358→                }));
   359→            }
   360→        }
   361→    };
   362→}
   363→

