     1→//! Adapters for WASM plugins to implement prb-detect and prb-core traits.
     2→
     3→use crate::runtime::WasmLimits;
     4→use bytes::Bytes;
     5→use extism::{Manifest, Plugin, Wasm};
     6→use prb_core::{CoreError, DebugEvent, DecodeContext, ProtocolDecoder, TransportKind};
     7→use prb_detect::{
     8→    DetectionContext, DetectionMethod, DetectionResult, DecoderFactory, ProtocolDetector,
     9→    ProtocolId, TransportLayer,
    10→};
    11→use prb_plugin_api::{DecodeCtx, DetectContext, PluginMetadata};
    12→use prb_plugin_api::types::WasmDecodeRequest;
    13→use std::path::PathBuf;
    14→use tracing::warn;
    15→
    16→/// Factory for creating WASM decoder instances.
    17→///
    18→/// Each call to create_decoder() instantiates a new WASM plugin instance,
    19→/// as WASM instances are not thread-safe or reentrant.
    20→pub struct WasmDecoderFactory {
    21→    plugin_path: PathBuf,
    22→    info: PluginMetadata,
    23→    limits: WasmLimits,
    24→}
    25→
    26→impl WasmDecoderFactory {
    27→    pub fn new(plugin_path: PathBuf, info: PluginMetadata, limits: WasmLimits) -> Self {
    28→        Self {
    29→            plugin_path,
    30→            info,
    31→            limits,
    32→        }
    33→    }
    34→}
    35→
    36→impl DecoderFactory for WasmDecoderFactory {
    37→    fn protocol_id(&self) -> ProtocolId {
    38→        ProtocolId::new(&self.info.protocol_id)
    39→    }
    40→
    41→    fn create_decoder(&self) -> Box<dyn ProtocolDecoder> {
    42→        // Each decoder instance gets its own WASM plugin instance
    43→        let manifest = Manifest::new([Wasm::file(&self.plugin_path)])
    44→            .with_memory_max(self.limits.memory_max_pages)
    45→            .with_timeout(self.limits.timeout);
    46→
    47→        let instance = Plugin::new(&manifest, [], true)
    48→            .expect("plugin already validated during load");
    49→
    50→        Box::new(WasmDecoderInstance { instance })
    51→    }
    52→}
    53→
    54→/// WASM decoder instance wrapping an Extism plugin.
    55→struct WasmDecoderInstance {
    56→    instance: Plugin,
    57→}
    58→
    59→impl ProtocolDecoder for WasmDecoderInstance {
    60→    fn protocol(&self) -> TransportKind {
    61→        // TODO: Wire through protocol from metadata
    62→        TransportKind::RawTcp
    63→    }
    64→
    65→    fn decode_stream(
    66→        &mut self,
    67→        data: &[u8],
    68→        ctx: &DecodeContext,
    69→    ) -> Result<Vec<DebugEvent>, CoreError> {
    70→        use base64::Engine;
    71→
    72→        // Prepare decode request
    73→        let request = WasmDecodeRequest {
    74→            data_b64: base64::engine::general_purpose::STANDARD.encode(data),
    75→            ctx: convert_decode_context(ctx),
    76→        };
    77→
    78→        let request_json = serde_json::to_string(&request)
    79→            .map_err(|e| CoreError::PayloadDecode(format!("serialize request: {}", e)))?;
    80→
    81→        // Call WASM decode function
    82→        let result_json = self
    83→            .instance
    84→            .call::<&str, String>("prb_plugin_decode", &request_json)
    85→            .map_err(|e| CoreError::PayloadDecode(format!("WASM decode call: {}", e)))?;
    86→
    87→        // Parse result
    88→        let dtos: Vec<prb_plugin_api::DebugEventDto> = serde_json::from_str(&result_json)
    89→            .map_err(|e| CoreError::PayloadDecode(format!("deserialize response: {}", e)))?;
    90→
    91→        // Convert DTOs to DebugEvents
    92→        dtos.into_iter()
    93→            .map(convert_dto_to_event)
    94→            .collect()
    95→    }
    96→}
    97→
    98→/// Protocol detector that uses WASM plugin.
    99→pub struct WasmProtocolDetector {
   100→    plugin_path: PathBuf,
   101→    info: PluginMetadata,
   102→    limits: WasmLimits,
   103→}
   104→
   105→impl WasmProtocolDetector {
   106→    pub fn new(plugin_path: PathBuf, info: PluginMetadata) -> Self {
   107→        Self {
   108→            plugin_path,
   109→            info,
   110→            limits: WasmLimits::for_detection(),
   111→        }
   112→    }
   113→}
   114→
   115→impl ProtocolDetector for WasmProtocolDetector {
   116→    fn name(&self) -> &str {
   117→        &self.info.name
   118→    }
   119→
   120→    fn transport(&self) -> TransportLayer {
   121→        // TODO: Wire through from plugin metadata
   122→        TransportLayer::Tcp
   123→    }
   124→
   125→    fn detect(&self, ctx: &DetectionContext<'_>) -> Option<DetectionResult> {
   126→        // Create a temporary plugin instance for detection
   127→        let manifest = Manifest::new([Wasm::file(&self.plugin_path)])
   128→            .with_memory_max(self.limits.memory_max_pages)
   129→            .with_timeout(self.limits.timeout);
   130→
   131→        let mut instance = match Plugin::new(&manifest, [], true) {
   132→            Ok(p) => p,
   133→            Err(e) => {
   134→                warn!(error = %e, "Failed to create plugin instance for detection");
   135→                return None;
   136→            }
   137→        };
   138→
   139→        // Prepare detect context
   140→        let detect_ctx = DetectContext {
   141→            initial_bytes: ctx.initial_bytes.to_vec(),
   142→            src_port: ctx.src_port,
   143→            dst_port: ctx.dst_port,
   144→            transport: match ctx.transport {
   145→                TransportLayer::Tcp => prb_plugin_api::TransportLayer::Tcp,
   146→                TransportLayer::Udp => prb_plugin_api::TransportLayer::Udp,
   147→            },
   148→        };
   149→
   150→        let ctx_json = match serde_json::to_string(&detect_ctx) {
   151→            Ok(j) => j,
   152→            Err(e) => {
   153→                warn!(error = %e, "Failed to serialize detect context");
   154→                return None;
   155→            }
   156→        };
   157→
   158→        // Call detect function
   159→        let result_json = match instance.call::<&str, String>("prb_plugin_detect", &ctx_json) {
   160→            Ok(r) => r,
   161→            Err(e) => {
   162→                warn!(error = %e, "WASM detect call failed");
   163→                return None;
   164→            }
   165→        };
   166→
   167→        // Parse confidence result
   168→        let confidence: Option<f32> = match serde_json::from_str(&result_json) {
   169→            Ok(c) => c,
   170→            Err(e) => {
   171→                warn!(error = %e, "Failed to parse detect result");
   172→                return None;
   173→            }
   174→        };
   175→
   176→        confidence.map(|c| DetectionResult {
   177→            protocol: ProtocolId::new(&self.info.protocol_id),
   178→            confidence: c,
   179→            method: DetectionMethod::Heuristic,
   180→            version: None,
   181→        })
   182→    }
   183→}
   184→
   185→/// Convert prb-core DecodeContext to plugin API DecodeCtx.
   186→fn convert_decode_context(ctx: &DecodeContext) -> DecodeCtx {
   187→    DecodeCtx {
   188→        src_addr: ctx.src_addr.clone(),
   189→        dst_addr: ctx.dst_addr.clone(),
   190→        timestamp_nanos: ctx.timestamp.as_ref().map(|ts| ts.as_nanos()),
   191→        metadata: ctx.metadata.iter().map(|(k, v)| (k.clone(), v.clone())).collect(),
   192→    }
   193→}
   194→
   195→/// Convert DebugEventDto to DebugEvent.
   196→fn convert_dto_to_event(
   197→    dto: prb_plugin_api::DebugEventDto,
   198→) -> Result<DebugEvent, CoreError> {
   199→    use prb_core::{Direction, EventSource, NetworkAddr, Payload, Timestamp};
   200→
