//! Tests for native plugin adapter.

use prb_plugin_api::{CorrelationKeyDto, DebugEventDto};
use std::collections::HashMap;

// Re-export the dto_to_debug_event function for testing
// We need to test the conversion logic without loading actual plugins
#[path = "../src/adapter.rs"]
mod adapter;

#[test]
fn test_dto_to_debug_event_minimal() {
    let dto = DebugEventDto::minimal("grpc", "request");
    let event = adapter::dto_to_debug_event(dto).expect("conversion should succeed");

    assert_eq!(event.transport, prb_core::TransportKind::Grpc);
    assert_eq!(event.direction, prb_core::Direction::Inbound);
    assert_eq!(event.timestamp.as_nanos(), 0);
}

#[test]
fn test_dto_to_debug_event_all_transports() {
    let transports = vec![
        ("grpc", prb_core::TransportKind::Grpc),
        ("http2", prb_core::TransportKind::Grpc),
        ("zmtp", prb_core::TransportKind::Zmq),
        ("zeromq", prb_core::TransportKind::Zmq),
        ("rtps", prb_core::TransportKind::DdsRtps),
        ("dds", prb_core::TransportKind::DdsRtps),
        ("tcp", prb_core::TransportKind::RawTcp),
        ("udp", prb_core::TransportKind::RawUdp),
        ("unknown", prb_core::TransportKind::JsonFixture),
    ];

    for (transport_str, expected_kind) in transports {
        let dto = DebugEventDto::minimal(transport_str, "request");
        let event = adapter::dto_to_debug_event(dto).expect("conversion should succeed");
        assert_eq!(event.transport, expected_kind, "failed for transport: {}", transport_str);
    }
}

